-- 002_password_reset_tokens.sql — single-use, expiring links for "forgot password".
--
-- Only a HASH of each token is stored, never the token itself. A leaked database
-- dump therefore hands an attacker nothing usable: they would have to invert
-- SHA-256 to produce a link that verifies.
--
-- SHA-256 rather than bcrypt, and that is a deliberate departure from how
-- users.password_hash works. bcrypt is slow *on purpose* because a password has
-- little entropy — it must be expensive to guess. A reset token is 32 random
-- bytes (256 bits) generated by the server, so guessing is already hopeless and
-- there is nothing for a slow KDF to buy. What we gain instead: a plain equality
-- lookup on an indexed column, because SHA-256 is deterministic while bcrypt
-- salts every call and could only be checked by scanning every row.

CREATE TABLE password_reset_tokens (
    id         BIGINT      GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    user_id    BIGINT      NOT NULL REFERENCES users (id) ON DELETE CASCADE,

    -- Hex SHA-256 of the token that went out in the email. UNIQUE so the same
    -- token can never be recorded twice.
    token_hash TEXT        NOT NULL UNIQUE,

    expires_at TIMESTAMPTZ NOT NULL,

    -- NULL until redeemed. Marking rather than deleting is what makes a token
    -- single-use *and* leaves an audit trail of when it was spent.
    used_at    TIMESTAMPTZ,

    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Requesting a new link invalidates a user's outstanding ones, which is a write
-- keyed on user_id. Without this index that is a sequential scan of the table.
CREATE INDEX password_reset_tokens_user_id_idx ON password_reset_tokens (user_id);
